INSERT INTO public.form_templates VALUES ('a4b04b84-0cda-4210-be1b-c46532c7570b', NULL, 'Qualificação Rápida', 'Formulário simples para qualificar leads rapidamente', 'qualification', NULL, '[{"label": "Bem-vindo!", "block_type": "welcome_screen", "description": "Responda algumas perguntas rápidas para conhecermos melhor suas necessidades."}, {"label": "Qual é o seu nome?", "maps_to": "name", "required": true, "block_type": "text", "placeholder": "Digite seu nome completo"}, {"label": "Qual é o seu email?", "maps_to": "email", "required": true, "block_type": "email", "placeholder": "seu@email.com"}, {"label": "Qual é o seu telefone?", "maps_to": "phone", "required": true, "block_type": "phone", "placeholder": "(00) 00000-0000"}, {"label": "Qual é o nome da sua empresa?", "maps_to": "company", "required": false, "block_type": "text", "placeholder": "Nome da empresa"}, {"label": "Quantos funcionários sua empresa tem?", "options": [{"label": "1 a 10", "value": "1-10"}, {"label": "11 a 50", "value": "11-50"}, {"label": "51 a 200", "value": "51-200"}, {"label": "Mais de 200", "value": "200+"}], "required": true, "block_type": "select", "score_rules": [{"score": 10, "value": "200+"}, {"score": 7, "value": "51-200"}, {"score": 5, "value": "11-50"}]}, {"label": "Obrigado!", "block_type": "end_screen", "description": "Entraremos em contato em breve."}]', '{"primary_color": "#8B5CF6"}', '{}', true, true, 0, NULL, '2026-01-22 19:21:19.00488+00', '2026-01-22 19:21:19.00488+00') ON CONFLICT DO NOTHING;
INSERT INTO public.form_templates VALUES ('26c83065-73ea-417d-961f-1744d14aa453', NULL, 'Diagnóstico Completo', 'Formulário para entender profundamente as necessidades do lead', 'diagnostic', NULL, '[{"label": "Vamos fazer um diagnóstico", "block_type": "welcome_screen", "description": "Em poucos minutos, vamos entender sua situação atual e como podemos ajudar."}, {"label": "Qual é o seu nome?", "maps_to": "name", "required": true, "block_type": "text"}, {"label": "Seu melhor email", "maps_to": "email", "required": true, "block_type": "email"}, {"label": "WhatsApp para contato", "maps_to": "phone", "required": true, "block_type": "phone"}, {"label": "Empresa", "maps_to": "company", "required": true, "block_type": "text"}, {"label": "Seu cargo", "maps_to": "position", "required": false, "block_type": "text"}, {"label": "De 1 a 10, qual sua urgência em resolver esse problema?", "options": {"max": 10, "min": 1}, "required": true, "block_type": "scale", "score_rules": [{"min": 8, "score": 10}, {"min": 5, "score": 5}]}, {"label": "Descreva brevemente seu principal desafio", "maps_to": "notes", "required": true, "block_type": "textarea"}, {"label": "Você tem orçamento disponível para investir em uma solução?", "required": true, "block_type": "yes_no", "score_rules": [{"score": 15, "value": true}]}, {"label": "Diagnóstico recebido!", "block_type": "end_screen", "description": "Um especialista entrará em contato em até 24h."}]', '{"primary_color": "#6366F1"}', '{}', true, true, 0, NULL, '2026-01-22 19:21:19.00488+00', '2026-01-22 19:21:19.00488+00') ON CONFLICT DO NOTHING;
