INSERT INTO public.platform_releases VALUES ('27bc24ff-14c8-4c2d-b09a-9f8048d8f325', '1.0', 'Central de Ajuda e Página de Atualizações', 'Agora você tem um espaço dedicado para tirar dúvidas e acompanhar tudo o que muda na plataforma.', '{feature}', NULL, '<h2>O que chegou</h2><p>Lançamos dois novos recursos:</p><ul><li><strong>Central de Ajuda</strong> (ícone de interrogação no topo): artigos organizados por categorias, com texto, imagens, links e vídeos.</li><li><strong>Novidades</strong> (ícone de estrelas no topo): timeline com tudo que muda na plataforma — novas features, melhorias e correções.</li></ul><h3>Como funciona</h3><p>O ícone de Novidades exibe um contador de itens não lidos. Cada release pode ser publicado também como artigo na Central de Ajuda, mantendo o conteúdo organizado por contexto.</p><p>Aproveite!</p>', NULL, true, '2026-04-25 10:32:24.326708+00', NULL, '2026-04-25 10:32:24.326708+00', '2026-04-25 10:32:24.326708+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('c7d484df-60e4-4e7e-a453-16b115ac2ca6', '474be65b-20db-4290-ade4-c0cb5d5ad491', 'bem-vindo-vendus', 'Bem-vindo à plataforma Vendus', 'Visão geral em 5 minutos sobre como navegar pelo CRM, gerenciar leads e usar a IA.', NULL, '<h2>Bem-vindo!</h2><p>A plataforma Vendus reúne em um só lugar a gestão de leads, atendimento por WhatsApp, agendamentos, IA copiloto e financeiro.</p><h3>O que você encontra aqui</h3><ul><li><strong>Pipeline e Kanban</strong> para mover leads pelas etapas de venda.</li><li><strong>Inbox</strong> para conversar com clientes via WhatsApp e chat do site.</li><li><strong>Agendamentos</strong> com integração ao Google Calendar.</li><li><strong>Agentes de IA</strong> que respondem dúvidas, qualificam leads e marcam reuniões.</li></ul><h3>Próximos passos</h3><ol><li>Configure seu perfil em <em>Configurações</em>.</li><li>Conecte seu WhatsApp em <em>Integrações</em>.</li><li>Crie seu primeiro funil de vendas.</li></ol><p>Tem dúvida? Use a busca aqui na Central de Ajuda ou clique no ícone de ajuda no topo de qualquer tela.</p>', NULL, '{}', true, 0, 1, 0, 0, NULL, NULL, '2026-04-25 10:32:24.326708+00', '2026-04-25 10:42:32.107628+00', '2026-04-25 10:32:24.326708+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('15813c3e-59f1-42ac-a074-92e1b749d3e9', '474be65b-20db-4290-ade4-c0cb5d5ad491', 'os-3-perfis-super-admin-admin-e-vendedor-quem-faz-o-que', 'Os 3 perfis: Super Admin, Admin e Vendedor — quem faz o quê', 'Entenda a hierarquia da plataforma e o que cada papel pode acessar.', NULL, '<h2>Três níveis, três responsabilidades</h2>
INSERT INTO public.help_articles VALUES ('f6688856-7a77-4098-bf31-06a93549cb36', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'cadencia-e-playbook-por-produto', 'Cadência e Playbook por produto', 'Sequência automática de toques + roteiro de venda.', NULL, '<h2>Cadência e Playbook por produto</h2><p><em>Sequência automática de toques + roteiro de venda.</em></p><p>Este artigo está sendo aprimorado.</p>', NULL, '{important}', true, 90, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('d09422a4-7fcd-4427-8de9-4d3b654bf484', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'materiais-subindo-pdfs-videos-e-links-para-o-time', 'Materiais: subindo PDFs, vídeos e links para o time', 'Centralize todo o material de venda por produto.', NULL, '<h2>Materiais</h2><p><em>Centralize todo o material de venda por produto.</em></p><p>Este artigo está sendo aprimorado.</p>', NULL, '{important}', true, 100, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('f42f18ea-e72f-482a-9063-1444bfb76d5c', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'objecoes-cadastrando-e-usando-o-assistente', 'Objeções: cadastrando e usando o assistente', 'Quebre objeções comuns com argumentos validados.', NULL, '<h2>Objeções</h2><p><em>Quebre objeções comuns com argumentos validados.</em></p><p>Este artigo está sendo aprimorado.</p>', NULL, '{important}', true, 110, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('00f5fc46-e2d4-40a5-a50c-4f8811b56906', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'campos-personalizados-em-leads', 'Campos personalizados em leads', 'Adicione campos específicos do seu negócio.', NULL, '<h2>Campos personalizados</h2><p><em>Adicione campos específicos do seu negócio.</em></p><p>Este artigo está sendo aprimorado.</p>', NULL, '{important}', true, 120, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('033e8af3-5a4c-4bc3-aeba-3222df163f44', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'notificacoes-automaticas-cron-gatilhos', 'Notificações automáticas (cron + gatilhos)', 'Configure alertas para o time sobre eventos importantes.', NULL, '<h2>Notificações automáticas</h2><p>Este artigo está sendo aprimorado.</p>', NULL, '{important}', true, 130, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('9825b86d-7ebd-4bc2-8aac-3eb32e3c458f', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'relatorios-vendas-conversao-performance-por-squad', 'Relatórios: vendas, conversão, performance por squad', 'Como interpretar os relatórios do painel.', NULL, '<h2>Relatórios</h2><p>Este artigo está sendo aprimorado.</p>', NULL, '{advanced}', true, 140, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('b6470c0d-51e1-49f8-8272-2d42afccfaaf', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'painel-super-admin-o-que-controlo-daqui', 'Painel Super Admin: o que controlo daqui', 'Visão geral dos seus poderes como dono da plataforma.', NULL, '<h2>O Painel Super Admin</h2><p>Daqui você opera a plataforma como produto SaaS: organizações, planos, cobrança, identidade visual White Label, servidores globais (Evolution Go, Resend, Firecrawl), Central de Ajuda, auditoria, saúde do sistema e leads comerciais.</p><h3>Como entrar</h3><p>No menu superior, clique em <strong>Super Admin</strong> (só aparece para usuários com role <em>super_admin</em>).</p>', NULL, '{essential}', true, 0, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('9d07f7e5-3d1c-4bdb-aec4-5a677dd7198b', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'criando-uma-nova-organizacao-cliente', 'Criando uma nova organização (cliente)', 'Passo a passo para subir um cliente novo.', NULL, '<h2>Nova organização</h2><ol><li>Super Admin → Organizações → + Nova.</li><li>Informe nome da empresa, e-mail do admin principal e plano.</li><li>Defina limites (ou herde do plano).</li><li>Clique em Criar.</li></ol><p>Convite é enviado para o admin definir senha e entrar.</p>', NULL, '{essential}', true, 10, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('d704e1d8-d704-46e1-b6cf-7db4bca754e6', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'gerenciando-planos-e-limites-por-organizacao', 'Gerenciando planos e limites por organização', 'Crie planos e ajuste limites caso a caso.', NULL, '<h2>Planos e limites</h2><p>Os planos definem o pacote padrão. Você pode sobrescrever limites por organização sem mudar o plano.</p><p>Limites: max_users, max_connections, max_sectors, max_products, max_contacts, max_messages_month, max_ai_tokens_month. Features: whatsapp, ai_agents, voice_agents, capture_funnels, etc.</p>', NULL, '{essential}', true, 20, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('768fc5f4-f1ce-4366-8182-51ceecb9bd74', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'identidade-visual-e-white-label-logo-cores-dominio', 'Identidade visual e White Label (logo, cores, domínio)', 'Personalização completa da plataforma para revenda.', NULL, '<h2>White Label</h2><p>Personalize logo, cores, favicon, nome e domínio em Super Admin → Branding. As alterações se aplicam a todas as organizações conforme política definida.</p>', NULL, '{important}', true, 30, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('fa32c3a3-74f2-4217-a8be-29605edd9ed1', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'configurando-o-servidor-evolution-go-global', 'Configurando o servidor Evolution Go global', 'URL e chave do servidor para todas as organizações.', NULL, '<h2>Evolution Go global</h2><p>Configure UMA vez o servidor Evolution em Super Admin → Configurações da plataforma. Todas as instâncias WhatsApp das organizações usarão essa URL e chave automaticamente.</p>', NULL, '{important}', true, 40, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('6aa1f6aa-4249-438a-a124-4e1fb54a622a', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'configurando-e-mail-resend-da-plataforma', 'Configurando e-mail (Resend) da plataforma', 'Domínio verificado para envios transacionais.', NULL, '<h2>E-mail Resend</h2><p>Configure o domínio verificado em Super Admin → E-mail. É usado para convites, recuperação de senha e notificações transacionais.</p>', NULL, '{important}', true, 50, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('a21cd727-e9fc-4a84-8f87-8707d7bbf836', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'leads-comerciais-pagina-vendas', 'Leads comerciais (página /vendas)', 'Quem demonstrou interesse na plataforma.', NULL, '<h2>Leads comerciais</h2><p>A página pública /vendas captura interessados na sua plataforma. Veja, qualifique e converta em organizações em Super Admin → Leads comerciais.</p>', NULL, '{important}', true, 60, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('6b440936-c07d-4245-b998-93df5467bf61', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'auditoria-e-logs-do-sistema', 'Auditoria e logs do sistema', 'Investigando ações em qualquer organização.', NULL, '<h2>Auditoria</h2><p>Em Super Admin → Auditoria você vê todas as ações sensíveis: criação/exclusão de usuários, mudança de planos, alterações em configurações. Filtre por organização, usuário ou tipo.</p>', NULL, '{important}', true, 70, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('8193fb17-4818-4269-a5b2-6a13e979e242', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'saude-do-sistema-e-metricas-globais', 'Saúde do sistema e métricas globais', 'Uptime, uso de tokens, erros e gargalos.', NULL, '<h2>Saúde do sistema</h2><p>Em Super Admin → System Health você acompanha consumo de tokens IA, status de filas, edge functions e métricas globais de todas as organizações.</p>', NULL, '{important}', true, 80, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('be0a4962-becb-4f5d-a252-5c4921cdaf5c', '11e3404f-6a4f-4ec6-a38d-17f52a78baee', 'publicando-atualizacoes-e-gerenciando-a-central-de-ajuda', 'Publicando atualizações e gerenciando a Central de Ajuda', 'Como criar releases que viram artigos automaticamente.', NULL, '<h2>Atualizações + Central de Ajuda</h2><p>Em Super Admin → Atualizações você publica releases (feature/improvement/fix). Marque <em>Publicar como artigo</em> para criar automaticamente um artigo correspondente na Central de Ajuda.</p>', NULL, '{advanced}', true, 90, 0, 0, 0, NULL, NULL, '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00', '2026-04-25 10:50:42.949449+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('7264e70c-24a8-4f2c-93e8-9aadbcd2a491', '474be65b-20db-4290-ade4-c0cb5d5ad491', 'convidar-equipe', 'Como convidar sua equipe', 'Envie convites por e-mail e defina papéis (admin, gerente, vendedor).', NULL, '<h2>Passo a passo</h2><ol><li>Vá em <strong>Configurações → Equipe</strong>.</li><li>Clique em <strong>Convidar membro</strong>.</li><li>Informe e-mail, papel (admin/gerente/vendedor) e squad opcional.</li><li>O convite é enviado por e-mail (Resend) e expira em 7 dias.</li><li>Ao aceitar, o usuário entra automaticamente na organização com permissões iniciais do papel.</li></ol><p><strong>Dica:</strong> ajuste permissões granulares depois em <em>Equipe → Permissões</em>.</p>', NULL, '{}', true, 4, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('eef5ed79-a84d-4c4e-90ef-c66b27082c8e', '474be65b-20db-4290-ade4-c0cb5d5ad491', 'primeira-conexao-whatsapp', 'Conectando seu primeiro WhatsApp', 'Escaneie o QR Code e comece a receber mensagens no Inbox.', NULL, '<h2>Conectar WhatsApp</h2><ol><li>Acesse <strong>Integrações → WhatsApp</strong>.</li><li>Clique em <strong>Nova conexão</strong> e escolha o provedor (Evolution Go é o padrão).</li><li>Escaneie o QR Code com o WhatsApp do celular.</li><li>Aguarde o status mudar para <strong>Conectado</strong>.</li><li>Direcione a conexão para um <em>setor</em> ou <em>squad</em> para começar a receber leads.</li></ol><p>Mensagens recebidas aparecem automaticamente no <strong>Inbox</strong>.</p>', NULL, '{}', true, 5, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('6b04213f-fac7-4c20-ac6e-d0aab9416ca5', 'a961fff4-8c95-4b53-88d3-6e3c0945fc9a', 'criar-etapas-pipeline', 'Configurando etapas do Pipeline', 'Crie, renomeie e reordene etapas por produto.', NULL, '<h2>Editar etapas</h2><ol><li>Vá em <strong>Produtos → [seu produto] → Pipeline</strong>.</li><li>Clique em <strong>Adicionar etapa</strong>.</li><li>Defina nome, cor e tipo (ativa, ganha, perdida).</li><li>Arraste para reordenar.</li></ol><p>Etapas marcadas como <strong>ganha</strong> ou <strong>perdida</strong> finalizam o lead automaticamente.</p>', NULL, '{}', true, 2, 1, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-27 18:37:48.811815+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('a73f72f9-08a9-4458-8a2f-0ef2f2a2ae70', '474be65b-20db-4290-ade4-c0cb5d5ad491', 'tour-da-plataforma', 'Tour rápido pela plataforma', 'Conheça as áreas principais: Inbox, Pipeline, Leads, Produtos, IA e Configurações.', NULL, '<h2>Áreas principais</h2><ul><li><strong>Inbox</strong>: central de atendimento omnichannel (WhatsApp, site, Instagram, Facebook).</li><li><strong>Pipeline</strong>: kanban de vendas com etapas e automações.</li><li><strong>Leads</strong>: base de contatos qualificados com histórico, BANT e auditoria.</li><li><strong>Produtos</strong>: catálogo de produtos/serviços com squads e regras de comissão.</li><li><strong>IA</strong>: agentes autônomos, copiloto e materiais de treinamento.</li><li><strong>Integrações</strong>: WhatsApp, Sankhya, Cakto, formulários, webhooks.</li></ul><p>Use o menu lateral para navegar e o ícone de ajuda no topo para abrir esta central a qualquer momento.</p>', NULL, '{}', true, 3, 1, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-29 18:09:39.453103+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('7c3ad074-f735-47e6-94f4-8c7e7772cda7', 'a961fff4-8c95-4b53-88d3-6e3c0945fc9a', 'qualificacao-bant', 'Qualificação BANT', 'Use o framework BANT (Budget, Authority, Need, Timing) para qualificar leads.', NULL, '<h2>Framework BANT</h2><p>O BANT é composto por 4 pilares com micro-perguntas guiadas:</p><ul><li><strong>Budget</strong> (orçamento): o lead tem verba?</li><li><strong>Authority</strong> (autoridade): é o decisor?</li><li><strong>Need</strong> (necessidade): qual a dor?</li><li><strong>Timing</strong> (momento): quando pretende decidir?</li></ul><p>Acesse pela aba <strong>Qualificação</strong> dentro do detalhe do lead. O score é calculado automaticamente conforme as respostas.</p>', NULL, '{}', true, 3, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('350f86af-0c94-41a6-8d24-0d29b600f784', 'a961fff4-8c95-4b53-88d3-6e3c0945fc9a', 'planos-precos', 'Planos e preços do produto', 'Cadastre múltiplos planos e use no Pipeline para fechar negócios.', NULL, '<h2>Cadastro de planos</h2><ol><li>Em <strong>Produtos → [produto] → Planos</strong>, clique em <strong>Novo plano</strong>.</li><li>Defina nome, valor, recorrência e descrição.</li><li>Salve. Os planos ficam disponíveis no card do lead para selecionar valor da negociação.</li></ol><p>O valor selecionado vira base para cálculo de <strong>comissão</strong> automática.</p>', NULL, '{}', true, 4, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('06a17647-2d35-4577-b18b-f6ea4d204b91', 'a961fff4-8c95-4b53-88d3-6e3c0945fc9a', 'distribuicao-leads', 'Distribuição automática (Bizon Auto Dispatch)', 'Round-robin, menos ocupado ou performance — escolha a estratégia.', NULL, '<h2>Como funciona</h2><p>Quando um lead chega, o sistema escolhe automaticamente o vendedor com base na configuração do squad:</p><ul><li><strong>Round-robin</strong>: distribui em rodízio.</li><li><strong>Menos ocupado</strong>: atribui a quem tem menos leads ativos.</li><li><strong>Performance</strong>: prioriza top performers.</li></ul><p>Vendedores precisam estar com status <strong>Online</strong> para receber. Caso ninguém esteja, o lead vai para a fila (<em>lead_queue</em>) e é distribuído quando alguém ficar disponível.</p>', NULL, '{}', true, 7, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('54a57ce1-a09b-4c86-94b7-2c3101a48b86', '36efc791-7fa3-49f2-9305-919af68e7db7', 'visao-geral-inbox', 'Visão geral do Inbox', 'Central omnichannel para WhatsApp, site, Instagram e Facebook.', NULL, '<h2>O Inbox</h2><p>O Inbox unifica conversas de todos os canais conectados. Você vê em uma lista única quem está aguardando, quem está em atendimento e o histórico completo.</p><h3>Filtros principais</h3><ul><li><strong>Aguardando</strong>: ainda sem atendente.</li><li><strong>Meus</strong>: conversas atribuídas a você.</li><li><strong>Setor</strong>: conversas do seu setor.</li><li><strong>Finalizados</strong>: encerrados.</li></ul>', NULL, '{}', true, 1, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('20aa3fc5-9b11-47fd-bacc-f852e0daf054', '36efc791-7fa3-49f2-9305-919af68e7db7', 'enviar-mensagens-midia', 'Enviando mensagens, áudios e arquivos', 'Texto, emojis, áudios gravados, fotos, documentos e respostas rápidas.', NULL, '<h2>Recursos de envio</h2><ul><li>Texto com formatação (negrito, itálico).</li><li>Emojis e GIFs.</li><li>Gravação de áudio direta no navegador.</li><li>Anexos: imagens, PDFs, documentos.</li><li><strong>Respostas rápidas</strong>: digite "/" para inserir templates salvos.</li></ul>', NULL, '{}', true, 3, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('847b0553-757c-4023-ab2f-b93ea151537c', '36efc791-7fa3-49f2-9305-919af68e7db7', 'acoes-mensagem', 'Editar, apagar, responder e encaminhar', 'Ações avançadas em mensagens já enviadas.', NULL, '<h2>Ações disponíveis</h2><ul><li><strong>Responder</strong>: cita a mensagem original.</li><li><strong>Editar</strong>: corrige o texto (sincroniza com o WhatsApp).</li><li><strong>Apagar</strong>: remove para todos.</li><li><strong>Encaminhar</strong>: envia para outra conversa.</li><li><strong>Favoritar</strong>: marca como importante.</li></ul>', NULL, '{}', true, 4, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('faf03f85-15f6-4608-94a3-b3c024e232a3', '36efc791-7fa3-49f2-9305-919af68e7db7', 'reativar-com-ia', 'Reativar lead com IA', 'Botão "Chamar com IA" envia mensagem personalizada para reengajar.', NULL, '<h2>Chamar com IA</h2><p>No detalhe da conversa, clique no ícone <strong>raio (Zap)</strong>. A IA analisa o histórico do lead e gera uma mensagem de reativação personalizada (ex.: lead frio há 7 dias). Você revisa e envia.</p><p>Recurso disponível para administradores e gerentes.</p>', NULL, '{}', true, 5, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('60dd8854-ac89-49c2-97f7-ec602dd81e43', '36efc791-7fa3-49f2-9305-919af68e7db7', 'transferir-conversa', 'Transferindo conversas entre setores', 'Mude o setor responsável sem perder o histórico.', NULL, '<h2>Como transferir</h2><ol><li>Na conversa, clique em <strong>Transferir</strong>.</li><li>Escolha setor de destino e (opcional) atendente específico.</li><li>Adicione observação para o próximo atendente.</li></ol><p>O histórico completo segue junto.</p>', NULL, '{}', true, 6, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('edf84d0c-2455-4d58-a29c-1dde1b036356', '36efc791-7fa3-49f2-9305-919af68e7db7', 'agendamentos-pelo-inbox', 'Agendando reuniões pelo Inbox', 'Crie eventos no calendário direto da conversa.', NULL, '<h2>Agendar</h2><ol><li>Na conversa, clique em <strong>Agendar</strong>.</li><li>Escolha data, hora, duração e tipo (reunião, ligação, visita).</li><li>O lead recebe confirmação automática.</li><li>O evento aparece no <strong>Calendário</strong> do vendedor.</li></ol>', NULL, '{}', true, 7, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('dbbb2a43-60a1-4782-a5be-8c0840bb18a7', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'o-que-sao-agentes-ia', 'O que são Agentes de IA', 'Atendentes virtuais autônomos que conversam, qualificam, agendam e movem leads no CRM.', NULL, '<h2>Agentes de IA</h2><p>São atendentes virtuais conectados aos canais (WhatsApp, site, Instagram) capazes de executar até <strong>18 ações reais no CRM</strong> via Tool Calling: qualificar leads (BANT), mover entre etapas, criar tarefas, agendar reuniões, transferir para humano, etc.</p><p>Cada agente tem personalidade, base de conhecimento (materiais de treinamento) e canais autorizados.</p>', NULL, '{}', true, 1, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('ed51e6de-00ea-4dbd-b1f0-27900246ae0e', '36efc791-7fa3-49f2-9305-919af68e7db7', 'assumir-conversa', 'Assumir uma conversa', 'Como pegar uma conversa da fila e iniciar atendimento.', NULL, '<h2>Manual Pickup</h2><ol><li>No Inbox, abra a aba <strong>Aguardando</strong>.</li><li>Clique em uma conversa e em <strong>Assumir</strong>.</li><li>A conversa fica travada para você (lock) — outros não podem abrir.</li><li>Para devolver à fila, use <strong>Liberar</strong>.</li></ol>', NULL, '{}', true, 2, 1, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-27 18:38:02.871672+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('17bb61ea-73af-4293-89b6-65278c7174f6', 'a961fff4-8c95-4b53-88d3-6e3c0945fc9a', 'transferir-leads', 'Transferindo leads entre vendedores', 'Faça transferências documentadas com motivo e auditoria.', NULL, '<h2>Transferência de carteira</h2><ol><li>No card do lead, clique nos 3 pontos → <strong>Transferir</strong>.</li><li>Escolha o novo vendedor ou squad.</li><li>Informe o motivo (obrigatório para auditoria).</li><li>Confirme.</li></ol><p>A transferência é registrada em <em>lead_notes</em> com data, autor e motivo.</p>', NULL, '{}', true, 6, 1, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-29 18:09:49.443269+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('519643e5-47a8-484b-a128-6cb692349a43', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'criar-agente-ia', 'Criando seu primeiro agente', 'Configure nome, personalidade, canais e base de conhecimento.', NULL, '<h2>Passo a passo</h2><ol><li>Acesse <strong>IA → Agentes → Novo agente</strong>.</li><li>Defina nome, persona (ex.: SDR consultivo) e tom de voz.</li><li>Selecione o produto vinculado.</li><li>Habilite canais: WhatsApp, Webchat, Instagram, Facebook, Funil, Widget.</li><li>Anexe materiais de treinamento (PDF, DOCX, links).</li><li>Salve e teste no <strong>Playground</strong>.</li></ol>', NULL, '{}', true, 2, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('9ef4be3a-9607-48af-9355-4a3664a767de', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'treinamento-materiais', 'Treinando o agente com materiais', 'Faça upload de PDFs, DOCX, sites e textos livres.', NULL, '<h2>Materiais de treinamento</h2><ul><li><strong>Documentos</strong>: PDF, DOCX, TXT.</li><li><strong>Sites</strong>: URL é processada via Firecrawl.</li><li><strong>Texto livre</strong>: cole conteúdo direto.</li><li><strong>FAQ</strong>: perguntas e respostas estruturadas.</li></ul><p>O conteúdo é processado, dividido em chunks e indexado para busca semântica (RAG).</p>', NULL, '{}', true, 3, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('bbf88192-a48f-4c14-a739-8ef84bd408c5', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'transicao-entre-agentes', 'Transição autônoma entre agentes', 'Use o bloco "ai_takeover" para trocar de agente conforme contexto.', NULL, '<h2>Como funciona</h2><p>Em fluxos de captura, o bloco <strong>ai_takeover</strong> permite que a IA escolha autonomamente trocar para outro agente (ex.: do SDR para o Closer ao detectar lead qualificado).</p><p>Configure regras de transição com gatilhos baseados em score, intenção ou palavras-chave.</p>', NULL, '{}', true, 4, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('45fac821-ca1d-4389-8e51-cb3fd53759f4', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'copiloto-vendas', 'Copiloto de Vendas', 'Sugestões em tempo real para o vendedor durante a conversa.', NULL, '<h2>O Copiloto</h2><p>No Inbox, o Copiloto sugere respostas estratégicas em formato de 3 partes:</p><ol><li><strong>O que ele quis dizer</strong>: análise da intenção.</li><li><strong>O que responder</strong>: mensagem sugerida.</li><li><strong>Por que</strong>: justificativa estratégica.</li></ol><p>Use SPIN Selling como framework consultivo padrão.</p>', NULL, '{}', true, 5, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('180ebe4a-fa18-429b-9dc0-c31f83a60d43', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'agendamento-autonomo-ia', 'Agendamento autônomo pela IA', 'Agente consulta agenda real e marca reuniões sozinho.', NULL, '<h2>Booking automatizado</h2><p>O agente consulta a disponibilidade real dos vendedores (configurada em <em>Agendamentos</em>), oferece horários ao lead e cria o evento no calendário ao confirmar.</p><p>Os horários oferecidos ficam persistidos no metadata da mensagem para evitar loops.</p>', NULL, '{}', true, 6, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('ae2ed4bb-5abb-4243-b00a-0559ebfadae9', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'cadencia-outreach', 'Cadência de Outreach (Follow-up)', 'Envios automatizados escalonados para reativar leads frios.', NULL, '<h2>Cadência</h2><p>Configure sequências de mensagens (dia 1, dia 3, dia 7…) que a IA envia automaticamente para leads que pararam de responder.</p><p>Os disparos respeitam <strong>horário comercial</strong> e timezone da organização.</p>', NULL, '{}', true, 7, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('c6fa2ebd-9755-4174-b2fc-f8fd3c8338db', 'b4a910b5-cfd3-4a3d-a003-85ea8d7a7e73', 'agentes-de-voz', 'Agentes de Voz', 'Atendentes que conversam por ligação telefônica.', NULL, '<h2>Voice Agents</h2><p>Disponível em planos com o recurso ativado. Integração com Twilio (telefonia) e ElevenLabs (voz natural).</p><p>Configure persona, script e disparos de chamada (recepção e ativa).</p>', NULL, '{}', true, 8, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('6f5c7fb1-d44b-433b-ab99-f4390b3df7fd', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'whatsapp-evolution', 'WhatsApp via Evolution Go', 'Provedor padrão multi-instância gerenciado pelo Super Admin.', NULL, '<h2>Evolution Go</h2><p>Servidor configurado uma única vez no painel Super Admin. Cada organização cria suas próprias instâncias e escaneia o QR Code.</p><p>Suporta múltiplas conexões por organização, com direcionamento por setor/squad.</p>', NULL, '{}', true, 1, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('32ca5e73-e919-4c28-859a-387cb538e103', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'whatsapp-isichat-botconversa', 'WhatsApp via IsiChat e BotConversa', 'Provedores alternativos para WhatsApp.', NULL, '<h2>Provedores alternativos</h2><ul><li><strong>IsiChat</strong>: token configurado nos secrets.</li><li><strong>BotConversa</strong>: API key + workspace.</li></ul><p>Ambos seguem o mesmo fluxo: criar conexão → escanear QR → vincular a setor.</p>', NULL, '{}', true, 2, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('ea77e2ad-1c41-49ed-b70c-62065635f26b', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'sankhya-erp', 'Integração com Sankhya ERP', 'Sincronização bidirecional de parceiros, produtos e pedidos.', NULL, '<h2>Sankhya</h2><p>Sincroniza:</p><ul><li><strong>TGFPAR</strong>: parceiros (clientes/fornecedores).</li><li><strong>TGFPRO</strong>: produtos.</li><li><strong>Pedidos</strong>: criação a partir de deals fechados.</li></ul><p>Configure credenciais em <strong>Integrações → Sankhya</strong>.</p>', NULL, '{}', true, 3, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('00a23931-6fca-4089-bc49-bdf064f11af7', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'cakto-pagamentos', 'Integração com Cakto', 'Receba notificações de pagamentos e mapeie ofertas a produtos.', NULL, '<h2>Cakto</h2><ol><li>No painel Cakto, configure o webhook para a URL fornecida em <strong>Integrações → Cakto</strong>.</li><li>Mapeie cada <em>offer_id</em> da Cakto a um produto da plataforma.</li><li>Pagamentos aprovados criam/atualizam leads e disparam automações.</li></ol>', NULL, '{}', true, 4, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('4ce4aed3-fb4d-410f-b746-20e857989007', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'facebook-lead-ads', 'Facebook Lead Ads', 'Receba leads do Facebook direto no CRM.', NULL, '<h2>Facebook Lead Ads</h2><ol><li>Conecte sua conta do Facebook Business em <strong>Integrações → Facebook</strong>.</li><li>Escolha as páginas e formulários a sincronizar.</li><li>Leads chegam automaticamente no Inbox e Pipeline com UTMs preservadas.</li></ol>', NULL, '{}', true, 5, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('ef546dac-7a8e-4d79-b9ea-bdeb8688cc54', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'formularios-publicos', 'Formulários públicos', 'Crie formulários em wizard estilo Typeform e capture leads.', NULL, '<h2>Formulários</h2><ol><li>Vá em <strong>Captura → Formulários → Novo</strong>.</li><li>Adicione perguntas (texto, múltipla escolha, telefone, e-mail).</li><li>Publique e compartilhe a URL pública (<code>/f/:slug</code>).</li><li>Cada submissão vira lead no CRM.</li></ol>', NULL, '{}', true, 6, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('5604ddf4-af4e-4c54-852b-6701edcd4c01', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'funis-captura', 'Funis de captura', 'Sequências interativas com IA para qualificar visitantes do site.', NULL, '<h2>Funis estratégicos</h2><p>Crie funis arrastando blocos (pergunta, IA, agendamento, condicional). Instale via <code>funnel-widget.js</code> no seu site.</p><p>Use <strong>Criar com IA</strong> para gerar funis completos a partir de um prompt de texto.</p>', NULL, '{}', true, 7, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('37d4a82a-56e9-4f65-87c8-c72036efe8a7', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'webhooks', 'Central de Webhooks', 'Receba e envie eventos para sistemas externos.', NULL, '<h2>Webhooks</h2><ul><li><strong>Entrada</strong>: cada webhook tem URL única; mapeie campos do payload para campos do lead.</li><li><strong>Saída</strong>: dispare eventos (lead criado, deal fechado etc.) para Zapier, n8n ou sua API.</li></ul>', NULL, '{}', true, 8, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('f3e5a996-8717-4861-899e-9044ace2eae0', '15e89367-dcca-43e0-a642-16bd2c6ba146', 'resend-emails', 'E-mails transacionais (Resend)', 'Convites, notificações e disparos automatizados.', NULL, '<h2>Resend</h2><p>API key configurada nos secrets. A plataforma usa para: convites de equipe, recuperação de senha, notificações de leads, cadências de e-mail e relatórios.</p>', NULL, '{}', true, 9, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('58517fe1-014e-4b6f-84ad-cdc125659f3c', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'permissoes-granulares', 'Permissões granulares', 'Controle fino do que cada usuário pode ver e fazer.', NULL, '<h2>Permissões por usuário</h2><p>Em <strong>Equipe → [usuário] → Permissões</strong>, controle:</p><ul><li>Ver conversas de outros usuários/setores.</li><li>Acessar Pipeline, Dashboard, Inbox, Grupos.</li><li>Gerenciar carteira de clientes.</li><li>Ver todos os cards do Kanban.</li><li>Modo de visualização de agendamentos (todos/meus).</li></ul>', NULL, '{}', true, 7, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('4406ef3c-1520-44b7-861a-555d728412b9', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'setores-squads', 'Setores e Squads', 'Organize a equipe por departamento e por time de vendas.', NULL, '<h2>Setores vs Squads</h2><ul><li><strong>Setores</strong>: agrupam atendimento (Comercial, Suporte, Financeiro). Conexões de WhatsApp são vinculadas a setores.</li><li><strong>Squads</strong>: times de vendas vinculados a um produto. Recebem leads via distribuição automática.</li></ul>', NULL, '{}', true, 8, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('adc934aa-fcc9-4f4f-a820-7ba293b727d3', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'dashboard-metricas', 'Dashboard e métricas', 'Acompanhe vendas, conversões e performance da equipe.', NULL, '<h2>Dashboard</h2><p>Métricas principais: leads novos, taxa de conversão por etapa, tempo médio de resposta, vendas por vendedor, faturamento por produto e ranking da equipe.</p><p>Filtre por período, produto, squad e canal de origem.</p>', NULL, '{}', true, 9, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('f4acda84-c42c-4518-acbd-863b6704a23e', '832cc6a0-567d-45df-8c29-23d1e5e10215', 'central-notificacoes-admin', 'Central de Notificações', 'Envie comunicados em massa para sua equipe.', NULL, '<h2>Notificações</h2><p>Em <strong>Admin → Notificações</strong>, envie comunicados:</p><ul><li>Para toda a organização.</li><li>Por produto.</li><li>Por squad ou setor.</li><li>Para usuários específicos.</li></ul>', NULL, '{}', true, 10, 0, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('f1a049e0-67d6-4924-8e5d-5b558ac7318a', 'a961fff4-8c95-4b53-88d3-6e3c0945fc9a', 'introducao-pipeline', 'Introdução ao Pipeline', 'Como funciona o kanban de vendas, etapas e movimentação de leads.', NULL, '<h2>O que é o Pipeline</h2><p>O Pipeline é o kanban visual onde você acompanha cada lead pelas etapas da venda (ex.: Novo → Qualificado → Proposta → Fechado).</p><h3>Funcionamento</h3><ul><li>Cada produto pode ter um pipeline próprio com etapas customizadas.</li><li>Arraste o card do lead entre colunas para registrar o avanço.</li><li>Cada movimentação fica registrada no histórico (lead_stage_history) para auditoria.</li><li>Etapas podem ter automações (mensagens, tarefas, notificações).</li></ul>', NULL, '{}', true, 1, 3, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-25 12:59:30.937592+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
INSERT INTO public.help_articles VALUES ('37bd327f-3d89-45da-b2a9-6ea2650c2fad', 'a961fff4-8c95-4b53-88d3-6e3c0945fc9a', 'comissoes', 'Como funcionam as comissões', 'Regras de comissão por produto, vendedor e percentual ou valor fixo.', NULL, '<h2>Configurar comissões</h2><ol><li>Vá em <strong>Produtos → [produto] → Comissões</strong>.</li><li>Crie uma regra padrão (aplicada a todos) ou por vendedor.</li><li>Escolha tipo: <em>percentual</em> ou <em>valor fixo</em>.</li><li>Defina limites mínimo e máximo (opcional).</li></ol><p>Quando um deal é fechado, a comissão é calculada e registrada na tabela <em>commissions</em> com status <strong>pendente</strong> até aprovação.</p>', NULL, '{}', true, 5, 1, 0, 0, NULL, NULL, '2026-04-25 10:59:40.258469+00', '2026-04-27 18:37:38.634738+00', '2026-04-25 10:59:40.258469+00') ON CONFLICT DO NOTHING;
